import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const Sidebar: React.FC = () => {
  const location = useLocation();
  const { user } = useAuth();
  const [isOpen, setIsOpen] = useState(true);

  const isActive = (path: string) => {
    return location.pathname === path || location.pathname.startsWith(path);
  };

  // Links base que todos veem
  const baseNavLinks = [
    { 
      path: '/dashboard', 
      label: 'Dashboard', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
        </svg>
      )
    },
    { 
      path: '/produtos', 
      label: 'Produtos', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
        </svg>
      )
    },
    { 
      path: '/fornecedores', 
      label: 'Fornecedores', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
        </svg>
      )
    },
    { 
      path: '/veiculos', 
      label: 'Veículos', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17a2 2 0 11-4 0 2 2 0 014 0zM19 17a2 2 0 11-4 0 2 2 0 014 0z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0" />
        </svg>
      )
    },
    { 
      path: '/transportes', 
      label: 'Transportes', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
        </svg>
      )
    },
    // o painel de rastreamento usa abas internas; dois links apenas apontam para a mesma rota
    { 
      path: '/rastreamento',
      label: 'Rastreamento GPS',
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />
        </svg>
      )
    },
    {
      path: '/historico',
      label: 'Histórico',
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
      )
    },
  ];

  // Links condicionais só para SUPER_ADMIN
  const navLinks = [...baseNavLinks];
  
  // Adicionar link de Tarefas apenas para ADMIN e OPERATOR
  if (user?.role === 'ADMIN' || user?.role === 'OPERATOR') {
    navLinks.push({
      path: '/tarefas',
      label: 'Tarefas',
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6M5 6h14M5 18h14" />
        </svg>
      )
    });
    
    // Adicionar link de Referrals apenas para ADMIN e OPERATOR
    navLinks.push({
      path: '/referrals',
      label: 'Referências',
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
        </svg>
      )
    });
  }

  if (user?.role === 'SUPER_ADMIN') {
    navLinks.push({
      path: '/superadmin',
      label: 'Super Admin',
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
        </svg>
      )
    });
  }

  return (
    <>
      {/* Sidebar Desktop */}
      <aside 
        className={`hidden md:flex md:flex-col bg-gradient-to-b from-[#0f172a] via-[#1e293b] to-[#0f172a] border-r border-[#334155] fixed left-0 top-16 bottom-0 z-40 transition-all duration-300 ${
          isOpen ? 'w-64' : 'w-20'
        }`}
      >
        {/* Botão Toggle */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="absolute -right-3 top-6 w-6 h-6 bg-gradient-to-r from-[#3b82f6] to-[#2563eb] rounded-full flex items-center justify-center text-white shadow-lg hover:shadow-xl transition-all hover:scale-110"
          title={isOpen ? 'Fechar sidebar' : 'Abrir sidebar'}
        >
          <svg 
            className={`w-4 h-4 transition-transform duration-300 ${isOpen ? '' : 'rotate-180'}`} 
            fill="none" 
            stroke="currentColor" 
            viewBox="0 0 24 24"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <nav className="flex-1 px-3 py-6 space-y-1 overflow-y-auto">
          {navLinks.map((link) => (
            <Link
              key={link.label}
              to={link.path}
              className={`flex items-center ${isOpen ? 'space-x-3 px-4' : 'justify-center px-2'} py-3 rounded-lg text-sm font-medium transition-all duration-200 group ${
                isActive(link.path)
                  ? 'bg-gradient-to-r from-[#3b82f6]/20 to-[#2563eb]/20 text-white border border-[#3b82f6]/30 shadow-lg'
                  : 'text-[#94a3b8] hover:bg-[#1e293b] hover:text-white hover:border hover:border-[#334155] hover:translate-x-1'
              }`}
              title={!isOpen ? link.label : ''}
            >
              <span className={`transition-transform ${isActive(link.path) ? 'scale-110' : 'group-hover:scale-110'}`}>
                {link.icon}
              </span>
              {isOpen && (
                <>
                  <span className="whitespace-nowrap">{link.label}</span>
                  {isActive(link.path) && (
                    <span className="ml-auto w-2 h-2 bg-blue-400 rounded-full animate-pulse"></span>
                  )}
                </>
              )}
            </Link>
          ))}
        </nav>

        {/* Footer da Sidebar */}
        {isOpen && (
          <div className="p-4 border-t border-[#334155] space-y-2">
            {/* Status do Sistema */}
            <div className="bg-gradient-to-r from-[#3b82f6]/10 to-[#2563eb]/10 rounded-lg p-3 border border-[#3b82f6]/20">
              <div className="flex items-center space-x-2 mb-2">
                <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div>
                <span className="text-xs font-semibold text-slate-300">Sistema Online</span>
              </div>
              <p className="text-xs text-slate-400">
                Versão 2.0.1 Beta
              </p>
            </div>
          </div>
        )}
      </aside>

      {/* Sidebar Mobile (Bottom Navigation) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-gradient-to-r from-[#0f172a] to-[#1e293b] border-t border-[#334155] z-50">
        <div className="flex justify-around items-center h-16 px-2">
          {navLinks.slice(0, 5).map((link) => (
            <Link
              key={link.label}
              to={link.path}
              className={`flex flex-col items-center justify-center space-y-1 px-3 py-2 rounded-lg transition-all ${
                isActive(link.path)
                  ? 'text-white bg-[#3b82f6]/20'
                  : 'text-[#94a3b8]'
              }`}
            >
              <span className={`${isActive(link.path) ? 'scale-110' : ''}`}>
                {link.icon}
              </span>
              <span className="text-xs font-medium">{link.label}</span>
            </Link>
          ))}
        </div>
      </nav>
    </>
  );
};

export default Sidebar;
